const VERSION="10.5",report=[];
const wait=(test,ms=12000)=>new Promise((resolve)=>{const start=Date.now(),timer=setInterval(()=>{if(test()||Date.now()-start>ms){clearInterval(timer);resolve(Boolean(test()));}},80);});
function status(text,error=false){const el=document.querySelector("#connection-status");if(el){el.textContent=text;el.classList.toggle("offline",error);}}
function note(name,state,detail=""){const row={name,state,detail,at:new Date().toISOString()};report.push(row);window.dispatchEvent(new CustomEvent("mirna:module-status",{detail:row}));}
async function load(name,path,test){note(name,"loading");try{await import(`${path}?v=${VERSION}`);if(test&&!await wait(test))throw new Error("não terminou de iniciar");note(name,"ready");return true;}catch(error){note(name,"error",String(error?.message||error));return false;}}
async function boot(){status("Preparando…");const ok=[];ok.push(await load("Planejador","/workspace.js",()=>window.__mirnaWorkspace&&document.querySelector("#workspace-root")));ok.push(await load("Central de dados","/data-hub.js",()=>window.__mirnaDataHub&&document.querySelector("#mirna-data-hub")));ok.push(await load("Proteção da agenda","/calendar-guard-v1.js",()=>window.__mirnaCalendarGuard));ok.push(await load("Agenda","/calendar-v6.js",()=>window.__mirnaCalendarV6));ok.push(await load("Ateliê","/atelier.js",()=>window.__mirnaAtelier&&document.querySelector("#atelie")));ok.push(await load("Migração da professora","/teacher-migration-v1.js",()=>window.__mirnaTeacherMigration));ok.push(await load("Fluxo da professora","/teacher-workflow-v1.js",()=>window.__mirnaTeacher&&document.querySelector("#teacher-workflow")));ok.push(await load("Rotinas recorrentes","/teacher-recurring-v1.js",()=>window.__mirnaTeacherRecurring&&document.querySelector("#teacher-recurring")));ok.push(await load("Navbar","/sidebar-v7.js",()=>document.querySelector(".mirna-sidebar-v7")));ok.push(await load("Navegação do Ateliê","/atelier-nav.js"));ok.push(await load("Runtime","/runtime-v5.js",()=>window.__mirnaRuntimeV5));ok.push(await load("Diagnóstico","/diagnostics-v1.js",()=>window.__mirnaDiagnostics&&document.querySelector("#system-diagnostics")));const failures=ok.filter(v=>!v).length;status(failures?`Modo parcial · ${failures} atenção`:"Tudo pronto",Boolean(failures));window.__mirnaBoot={version:VERSION,report:()=>structuredClone(report),retry:()=>location.reload()};window.dispatchEvent(new CustomEvent("mirna:boot-complete",{detail:{failures,report}}));}
boot().catch(error=>{note("Inicialização","error",String(error?.message||error));status("Modo local",true);});
